using System;
using System.Collections.ObjectModel;
using System.Globalization;
using System.Linq;
using System.Threading.Tasks;
using System.Windows.Input;
using example-project.App.Shared;
using example-project.Application.Common.Enums;
using example-project.Application.Tax;

namespace example-project.App.Tax;

public sealed class JurisdictionListViewModel : BindableBase
{
    private readonly ITaxLookupService _jurisdictionService;
    private readonly ITaxAdministrationService _administrationService;

    private string _newName = string.Empty;
    private TaxJurisdictionTypeDto _newType = TaxJurisdictionTypeDto.County;
    private bool _newIsDefault;
    private string? _createError;
    private string _editName = string.Empty;
    private TaxJurisdictionTypeDto _editType = TaxJurisdictionTypeDto.State;
    private bool _editIsDefault;
    private string? _editError;

    private TaxJurisdictionSummary? _selectedJurisdiction;
    private TaxRateHistoryEntry? _selectedRate;
    private string _newRate = string.Empty;
    private DateTime? _newEffectiveFrom = DateTime.Today;
    private DateTime? _newEffectiveTo;
    private string? _addRateError;
    private string? _removeRateError;
    private string _removeAuditNote = string.Empty;
    private Guid? _editingRateId;
    private string _editRate = string.Empty;
    private DateTime? _editEffectiveFrom;
    private DateTime? _editEffectiveTo;
    private string? _editAuditNote;
    private string? _editRateError;
    private TaxRateHistoryEntry? _editingOriginalRate;
    private RateEditPreview? _editPreview;
    private UpdateTaxRateRequest? _pendingRateUpdate;
    private bool _isLoading;

    private readonly AsyncRelayCommand _updateJurisdictionCommand;
    private readonly AsyncRelayCommand<TaxRateHistoryEntry?> _beginEditRateCommand;
    private readonly AsyncRelayCommand _cancelEditRateCommand;
    private readonly AsyncRelayCommand _saveRateEditCommand;
    private readonly AsyncRelayCommand _confirmRateEditCommand;
    private readonly AsyncRelayCommand _dismissEditConfirmationCommand;

    public JurisdictionListViewModel(ITaxLookupService jurisdictionService, ITaxAdministrationService administrationService)
    {
        _jurisdictionService = jurisdictionService ?? throw new ArgumentNullException(nameof(jurisdictionService));
        _administrationService = administrationService ?? throw new ArgumentNullException(nameof(administrationService));
        Jurisdictions = new ObservableCollection<TaxJurisdictionSummary>();
        CreateCommand = new AsyncRelayCommand(CreateJurisdictionAsync, CanCreateJurisdiction);
        _updateJurisdictionCommand = new AsyncRelayCommand(UpdateJurisdictionAsync, CanUpdateJurisdiction);
        UpdateJurisdictionCommand = _updateJurisdictionCommand;
        AddRateCommand = new AsyncRelayCommand(AddRateAsync, CanAddRate);
        RemoveRateCommand = new AsyncRelayCommand(RemoveRateAsync, CanRemoveRate);
        _beginEditRateCommand = new AsyncRelayCommand<TaxRateHistoryEntry?>(entry =>
        {
            BeginEditRate(entry);
            return Task.CompletedTask;
        }, entry => entry is { Status: TaxRateStatus.Future });
        _cancelEditRateCommand = new AsyncRelayCommand(() =>
        {
            CancelEditRate();
            return Task.CompletedTask;
        }, () => IsEditingRate);
        _saveRateEditCommand = new AsyncRelayCommand(SaveRateEditAsync, () => IsEditingRate && !IsEditConfirmationVisible);
        _confirmRateEditCommand = new AsyncRelayCommand(ConfirmRateEditAsync, () => IsEditingRate && IsEditConfirmationVisible);
        _dismissEditConfirmationCommand = new AsyncRelayCommand(DismissEditConfirmationAsync, () => IsEditConfirmationVisible);
        BeginEditRateCommand = _beginEditRateCommand;
        CancelEditRateCommand = _cancelEditRateCommand;
        SaveRateEditCommand = _saveRateEditCommand;
        ConfirmRateEditCommand = _confirmRateEditCommand;
        DismissEditConfirmationCommand = _dismissEditConfirmationCommand;
        JurisdictionTypes = (TaxJurisdictionTypeDto[])Enum.GetValues(typeof(TaxJurisdictionTypeDto));
    }



    public ObservableCollection<TaxJurisdictionSummary> Jurisdictions { get; }
    public ObservableCollection<TaxJurisdictionSummary> Items => Jurisdictions;

    public ICommand CreateCommand { get; }

    public ICommand UpdateJurisdictionCommand { get; }

    public ICommand AddRateCommand { get; }

    public ICommand RemoveRateCommand { get; }

    public ICommand BeginEditRateCommand { get; }

    public ICommand CancelEditRateCommand { get; }

    public ICommand SaveRateEditCommand { get; }

    public ICommand ConfirmRateEditCommand { get; }

    public ICommand DismissEditConfirmationCommand { get; }

    public TaxJurisdictionTypeDto[] JurisdictionTypes { get; }

    public bool IsLoading
    {
        get => _isLoading;
        set => Set(ref _isLoading, value);
    }

    public TaxJurisdictionSummary? SelectedJurisdiction
    {
        get => _selectedJurisdiction;
        set
        {
            if (!Equals(_selectedJurisdiction, value))
            {
                ClearEditState();
                _selectedJurisdiction = value;
                OnPropertyChanged();
                OnPropertyChanged(nameof(HasSelectedJurisdiction));
                OnPropertyChanged(nameof(SelectedJurisdictionDisplay));
                OnPropertyChanged(nameof(SelectedJurisdictionTypeDisplay));
                SyncEditFields();
                _updateJurisdictionCommand.RaiseCanExecuteChanged();
                ((AsyncRelayCommand)AddRateCommand).RaiseCanExecuteChanged();
                ((AsyncRelayCommand)RemoveRateCommand).RaiseCanExecuteChanged();
                SelectedRate = _selectedJurisdiction?.RateHistory.FirstOrDefault();
            }
        }
    }

    public TaxRateHistoryEntry? SelectedRate
    {
        get => _selectedRate;
        set
        {
            if (!Equals(_selectedRate, value))
            {
                _selectedRate = value;
                OnPropertyChanged();
                ((AsyncRelayCommand)RemoveRateCommand).RaiseCanExecuteChanged();
            }
        }
    }

    public string NewName
    {
        get => _newName;
        set
        {
            if (_newName != value)
            {
                _newName = value;
                OnPropertyChanged();
                ((AsyncRelayCommand)CreateCommand).RaiseCanExecuteChanged();
            }
        }
    }

    public TaxJurisdictionTypeDto NewType
    {
        get => _newType;
        set
        {
            if (_newType != value)
            {
                _newType = value;
                OnPropertyChanged();
                if (_newType != TaxJurisdictionTypeDto.State)
                {
                    NewIsDefault = false;
                }
                ((AsyncRelayCommand)CreateCommand).RaiseCanExecuteChanged();
            }
        }
    }

    public bool NewIsDefault
    {
        get => _newIsDefault;
        set
        {
            if (_newIsDefault != value)
            {
                _newIsDefault = value;
                OnPropertyChanged();
            }
        }
    }

    public string? CreateError
    {
        get => _createError;
        private set
        {
            if (_createError != value)
            {
                _createError = value;
                OnPropertyChanged();
            }
        }
    }

    public string EditName
    {
        get => _editName;
        set
        {
            var newValue = value ?? string.Empty;
            if (_editName != newValue)
            {
                _editName = newValue;
                EditError = null;
                OnPropertyChanged();
                _updateJurisdictionCommand.RaiseCanExecuteChanged();
            }
        }
    }

    public TaxJurisdictionTypeDto EditType
    {
        get => _editType;
        set
        {
            if (_editType != value)
            {
                _editType = value;
                EditError = null;
                OnPropertyChanged();
                if (_editType != TaxJurisdictionTypeDto.State)
                {
                    EditIsDefault = false;
                }
                _updateJurisdictionCommand.RaiseCanExecuteChanged();
            }
        }
    }

    public bool EditIsDefault
    {
        get => _editIsDefault;
        set
        {
            if (_editIsDefault != value)
            {
                _editIsDefault = value;
                EditError = null;
                OnPropertyChanged();
                _updateJurisdictionCommand.RaiseCanExecuteChanged();
            }
        }
    }

    public string? EditError
    {
        get => _editError;
        private set
        {
            if (_editError != value)
            {
                _editError = value;
                OnPropertyChanged();
            }
        }
    }

    public bool HasSelectedJurisdiction => SelectedJurisdiction is { Id: var id } && id != Guid.Empty;

    public string SelectedJurisdictionDisplay => HasSelectedJurisdiction
        ? SelectedJurisdiction!.Name
        : "No selection";

    public string? SelectedJurisdictionTypeDisplay => HasSelectedJurisdiction
        ? $"({SelectedJurisdiction!.Type})"
        : null;

    public string NewRate
    {
        get => _newRate;
        set
        {
            if (_newRate != value)
            {
                _newRate = value;
                OnPropertyChanged();
                ((AsyncRelayCommand)AddRateCommand).RaiseCanExecuteChanged();
            }
        }
    }

    public DateTime? NewEffectiveFrom
    {
        get => _newEffectiveFrom;
        set
        {
            if (_newEffectiveFrom != value)
            {
                _newEffectiveFrom = value;
                OnPropertyChanged();
                ((AsyncRelayCommand)AddRateCommand).RaiseCanExecuteChanged();
            }
        }
    }

    public DateTime? NewEffectiveTo
    {
        get => _newEffectiveTo;
        set
        {
            if (_newEffectiveTo != value)
            {
                _newEffectiveTo = value;
                OnPropertyChanged();
            }
        }
    }

    public string? AddRateError
    {
        get => _addRateError;
        private set
        {
            if (_addRateError != value)
            {
                _addRateError = value;
                OnPropertyChanged();
            }
        }
    }

    public string? RemoveRateError
    {
        get => _removeRateError;
        private set
        {
            if (_removeRateError != value)
            {
                _removeRateError = value;
                OnPropertyChanged();
            }
        }
    }

    public string RemoveAuditNote
    {
        get => _removeAuditNote;
        set
        {
            var newValue = value ?? string.Empty;
            if (_removeAuditNote != newValue)
            {
                _removeAuditNote = newValue;
                OnPropertyChanged();
            }
        }
    }

    public bool IsEditingRate => _editingRateId.HasValue;

    public Guid? EditingRateId => _editingRateId;

    public string EditRate
    {
        get => _editRate;
        set
        {
            var newValue = value ?? string.Empty;
            if (_editRate != newValue)
            {
                _editRate = newValue;
                OnPropertyChanged();
                EditRateError = null;
            }
        }
    }

    public DateTime? EditEffectiveFrom
    {
        get => _editEffectiveFrom;
        set
        {
            if (_editEffectiveFrom != value)
            {
                _editEffectiveFrom = value;
                OnPropertyChanged();
            }
        }
    }

    public DateTime? EditEffectiveTo
    {
        get => _editEffectiveTo;
        set
        {
            if (_editEffectiveTo != value)
            {
                _editEffectiveTo = value;
                OnPropertyChanged();
            }
        }
    }

    public string? EditAuditNote
    {
        get => _editAuditNote;
        set
        {
            var newValue = string.IsNullOrWhiteSpace(value) ? null : value!.Trim();
            if (_editAuditNote != newValue)
            {
                _editAuditNote = newValue;
                OnPropertyChanged();
            }
        }
    }

    public string? EditRateError
    {
        get => _editRateError;
        private set
        {
            if (_editRateError != value)
            {
                _editRateError = value;
                OnPropertyChanged();
            }
        }
    }

    public RateEditPreview? EditPreview
    {
        get => _editPreview;
        private set
        {
            if (!Equals(_editPreview, value))
            {
                _editPreview = value;
                OnPropertyChanged();
                OnPropertyChanged(nameof(IsEditConfirmationVisible));
                _saveRateEditCommand?.RaiseCanExecuteChanged();
                _confirmRateEditCommand?.RaiseCanExecuteChanged();
                _dismissEditConfirmationCommand?.RaiseCanExecuteChanged();
            }
        }
    }

    public bool IsEditConfirmationVisible => EditPreview is not null;

    public async Task LoadAsync()
    {
        IsLoading = true;
        try
        {
            var selectedId = SelectedJurisdiction?.Id;
            var selectedRateId = SelectedRate?.Id;

            Jurisdictions.Clear();
            var data = await _jurisdictionService.GetAllAsync();
            foreach (var jurisdiction in data)
            {
                Items.Add(jurisdiction);
            }

            if (Jurisdictions.Count == 0)
            {
                Jurisdictions.Add(new TaxJurisdictionSummary(Guid.Empty, "(No jurisdictions configured)", TaxJurisdictionTypeDto.State, null, null, null, false, Array.Empty<TaxRateHistoryEntry>()));
                SelectedJurisdiction = Jurisdictions[0];
                SelectedRate = null;
            }
            else if (selectedId.HasValue)
            {
                SelectedJurisdiction = Jurisdictions.FirstOrDefault(j => j.Id == selectedId) ?? Jurisdictions[0];
            }
            else
            {
                SelectedJurisdiction = Jurisdictions[0];
            }

            if (SelectedJurisdiction is not null)
            {
                var matchedRate = SelectedJurisdiction.RateHistory.FirstOrDefault(r => r.Id == selectedRateId);
                if (matchedRate is null)
                {
                    matchedRate = SelectedJurisdiction.RateHistory.FirstOrDefault(r => r.Status == TaxRateStatus.Future) ??
                                  SelectedJurisdiction.RateHistory.FirstOrDefault();
                }

                SelectedRate = matchedRate;
            }
            else
            {
                SelectedRate = null;
            }

            ((AsyncRelayCommand)RemoveRateCommand).RaiseCanExecuteChanged();

            if (IsEditingRate)
            {
                var editingEntry = SelectedJurisdiction?.RateHistory.FirstOrDefault(r => r.Id == _editingRateId);
                if (editingEntry is null)
                {
                    ClearEditState();
                }
                else
                {
                    BeginEditRate(editingEntry);
                }
            }
        }
        finally
        {
            IsLoading = false;
        }
    }

    private void SyncEditFields()
    {
        EditError = null;

        if (SelectedJurisdiction is null || SelectedJurisdiction.Id == Guid.Empty)
        {
            EditName = string.Empty;
            EditType = TaxJurisdictionTypeDto.State;
            EditIsDefault = false;
            return;
        }

        EditName = SelectedJurisdiction.Name;
        EditType = SelectedJurisdiction.Type;
        EditIsDefault = SelectedJurisdiction.IsDefault;
    }

    private bool CanCreateJurisdiction() => !string.IsNullOrWhiteSpace(NewName);

    private bool CanUpdateJurisdiction()
    {
        if (SelectedJurisdiction is null || SelectedJurisdiction.Id == Guid.Empty)
        {
            return false;
        }

        return !string.IsNullOrWhiteSpace(EditName);
    }

    private async Task CreateJurisdictionAsync()
    {
        if (!CanCreateJurisdiction())
        {
            return;
        }

        try
        {
            CreateError = null;
            await _administrationService.CreateJurisdictionAsync(new CreateTaxJurisdictionRequest(NewName.Trim(), NewType, NewIsDefault));
            await LoadAsync();
            RemoveAuditNote = string.Empty;
            NewName = string.Empty;
            NewIsDefault = false;
        }
        catch (Exception ex)
        {
            CreateError = ex.Message;
        }
    }

    private bool CanAddRate()
    {
        if (SelectedJurisdiction is null)
        {
            return false;
        }

        if (!decimal.TryParse(NewRate, NumberStyles.Number, CultureInfo.CurrentCulture, out var parsedRate))
        {
            return false;
        }

        return parsedRate >= 0m && NewEffectiveFrom.HasValue;
    }

    private async Task AddRateAsync()
    {
        if (!CanAddRate() || SelectedJurisdiction is null)
        {
            return;
        }

        try
        {
            AddRateError = null;

            if (!TryParseRate(NewRate, out var parsedRate, out var parseError))
            {
                AddRateError = parseError;
                return;
            }

            if (NewEffectiveFrom is null)
            {
                AddRateError = "Effective from date is required.";
                return;
            }

            var effectiveFrom = DateOnly.FromDateTime(NewEffectiveFrom.Value);
            DateOnly? effectiveTo = null;

            if (NewEffectiveTo.HasValue)
            {
                effectiveTo = DateOnly.FromDateTime(NewEffectiveTo.Value);
                if (effectiveTo.Value < effectiveFrom)
                {
                    AddRateError = "Effective to date must be on or after effective from date.";
                    return;
                }
            }

            await _administrationService.AddRateAsync(new CreateTaxRateRequest(SelectedJurisdiction.Id, parsedRate, effectiveFrom, effectiveTo));
            await LoadAsync();
            RemoveAuditNote = string.Empty;

            NewRate = string.Empty;
            NewEffectiveTo = null;
        }
        catch (Exception ex)
        {
            AddRateError = ex.Message;
        }
    }

    private void BeginEditRate(TaxRateHistoryEntry? entry)
    {
        if (entry is null)
        {
            return;
        }

        if (_editingRateId == entry.Id)
        {
            SelectedRate = entry;
            return;
        }

        ClearEditState();
        _editingRateId = entry.Id;
        OnPropertyChanged(nameof(EditingRateId));
        OnPropertyChanged(nameof(IsEditingRate));
        EditRateError = null;
        _editingOriginalRate = entry;

        var culture = CultureInfo.CurrentCulture;
        EditRate = (entry.Rate * 100m).ToString("0.##", culture);
        EditEffectiveFrom = entry.EffectiveFrom.ToDateTime(TimeOnly.MinValue);
        EditEffectiveTo = entry.EffectiveTo?.ToDateTime(TimeOnly.MinValue);
        EditAuditNote = null;
        SelectedRate = entry;

        _saveRateEditCommand?.RaiseCanExecuteChanged();
        _cancelEditRateCommand?.RaiseCanExecuteChanged();
        _confirmRateEditCommand?.RaiseCanExecuteChanged();
        _dismissEditConfirmationCommand?.RaiseCanExecuteChanged();
    }

    private void CancelEditRate()
    {
        if (!IsEditingRate)
        {
            return;
        }

        ClearEditState();
    }

    private Task SaveRateEditAsync()
    {
        if (!IsEditingRate || SelectedJurisdiction is null || !_editingRateId.HasValue)
        {
            return Task.CompletedTask;
        }

        if (IsEditConfirmationVisible)
        {
            return Task.CompletedTask;
        }

        if (!TryParseRate(EditRate, out var parsedRate, out var error))
        {
            EditRateError = error;
            return Task.CompletedTask;
        }

        if (EditEffectiveFrom is null)
        {
            EditRateError = "Effective from date is required.";
            return Task.CompletedTask;
        }

        var effectiveFrom = DateOnly.FromDateTime(EditEffectiveFrom.Value);
        DateOnly? effectiveTo = null;

        if (EditEffectiveTo.HasValue)
        {
            effectiveTo = DateOnly.FromDateTime(EditEffectiveTo.Value);
            if (effectiveTo.Value < effectiveFrom)
            {
                EditRateError = "Effective to date must be on or after effective from date.";
                return Task.CompletedTask;
            }
        }

        var auditNote = string.IsNullOrWhiteSpace(EditAuditNote) ? null : EditAuditNote!.Trim();

        var original = _editingOriginalRate ?? SelectedJurisdiction.RateHistory.FirstOrDefault(r => r.Id == _editingRateId.Value);
        if (original is null)
        {
            EditRateError = "Original rate details could not be determined. Please reload and try again.";
            return Task.CompletedTask;
        }

        EditRateError = null;

        var pendingRequest = new UpdateTaxRateRequest(_editingRateId.Value, parsedRate, effectiveFrom, effectiveTo, auditNote);
        _pendingRateUpdate = pendingRequest;

        EditPreview = new RateEditPreview(
            pendingRequest.TaxRateId,
            SelectedJurisdiction.Name,
            SelectedJurisdiction.Type,
            original.Rate,
            parsedRate,
            original.EffectiveFrom,
            original.EffectiveTo,
            effectiveFrom,
            effectiveTo,
            auditNote);

        return Task.CompletedTask;
    }

    private async Task ConfirmRateEditAsync()
    {
        if (!IsEditingRate || _pendingRateUpdate is null)
        {
            return;
        }

        try
        {
            EditRateError = null;
            var editedId = _pendingRateUpdate.TaxRateId;

            await _administrationService.UpdateRateAsync(_pendingRateUpdate).ConfigureAwait(true);

            EditPreview = null;
            _pendingRateUpdate = null;
            ClearEditState();
            await LoadAsync().ConfigureAwait(true);

            if (SelectedJurisdiction is not null)
            {
                SelectedRate = SelectedJurisdiction.RateHistory.FirstOrDefault(r => r.Id == editedId);
            }
        }
        catch (Exception ex)
        {
            EditRateError = ex.Message;
        }
    }

    private async Task UpdateJurisdictionAsync()
    {
        if (!CanUpdateJurisdiction() || SelectedJurisdiction is null)
        {
            return;
        }

        try
        {
            EditError = null;
            var isDefault = EditType == TaxJurisdictionTypeDto.State && EditIsDefault;

            await _administrationService.UpdateJurisdictionAsync(
                new UpdateTaxJurisdictionRequest(
                    SelectedJurisdiction.Id,
                    EditName.Trim(),
                    EditType,
                    isDefault));

            await LoadAsync();
        }
        catch (Exception ex)
        {
            EditError = ex.Message;
        }
    }

    private Task DismissEditConfirmationAsync()
    {
        if (!IsEditConfirmationVisible)
        {
            return Task.CompletedTask;
        }

        _pendingRateUpdate = null;
        EditPreview = null;
        return Task.CompletedTask;
    }

    private void ClearEditState()
    {
        _pendingRateUpdate = null;
        _editingOriginalRate = null;
        if (EditPreview is not null)
        {
            EditPreview = null;
        }

        if (_editingRateId.HasValue)
        {
            _editingRateId = null;
            OnPropertyChanged(nameof(EditingRateId));
            OnPropertyChanged(nameof(IsEditingRate));
        }

        EditRate = string.Empty;
        EditEffectiveFrom = null;
        EditEffectiveTo = null;
        EditAuditNote = null;
        EditRateError = null;

        _saveRateEditCommand?.RaiseCanExecuteChanged();
        _cancelEditRateCommand?.RaiseCanExecuteChanged();
        _confirmRateEditCommand?.RaiseCanExecuteChanged();
        _dismissEditConfirmationCommand?.RaiseCanExecuteChanged();
    }

    private static bool TryParseRate(string value, out decimal rate, out string? error)
    {
        if (!decimal.TryParse(value, NumberStyles.Number, CultureInfo.CurrentCulture, out var parsed))
        {
            error = "Rate must be a number.";
            rate = 0m;
            return false;
        }

        if (parsed > 1m)
        {
            parsed /= 100m;
        }

        if (parsed < 0m || parsed > 1m)
        {
            error = "Rate must be between 0 and 100%.";
            rate = 0m;
            return false;
        }

        rate = parsed;
        error = null;
        return true;
    }



    private bool CanRemoveRate()
    {
        return !IsEditingRate && SelectedRate is { Status: TaxRateStatus.Future };
    }

    private async Task RemoveRateAsync()
    {
        if (!CanRemoveRate() || SelectedRate is null)
        {
            return;
        }

        try
        {
            RemoveRateError = null;
            await _administrationService.RemoveRateAsync(SelectedRate.Id, string.IsNullOrWhiteSpace(RemoveAuditNote) ? null : RemoveAuditNote.Trim());
            await LoadAsync();
            RemoveAuditNote = string.Empty;
        }
        catch (Exception ex)
        {
            RemoveRateError = ex.Message;
        }
    }
}

